+    }
+    let basis_points = total_errors
+        .saturating_mul(10_000)
+        .saturating_div(total_calls.max(1));
+    let whole = basis_points / 100;
+    let fractional = basis_points % 100;
+    format!("{whole}.{fractional:02}")
