+            return Cmd::None;
+        }
+        if let Event::Mouse(mouse) = event {
+            if matches!(mouse.kind, MouseEventKind::Down(MouseButton::Left)) {
+                let modal_area = quick_reply_modal_rect(self.screen_area());
